import axios from 'axios';

// Configuração com timeout e headers padrão
const api = axios.create({
  baseURL: 'http://localhost:5000/api/clientes',
  timeout: 10000, // 10 segundos
  headers: {
    'Content-Type': 'application/json',
  }
});

// Interceptor para tratamento global de erros
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response) {
      // Erros 4xx/5xx
      const errorMessage = error.response.data?.error || 
                         `Erro ${error.response.status}: ${error.response.statusText}`;
      return Promise.reject(new Error(errorMessage));
    } else if (error.request) {
      // Sem resposta do servidor
      return Promise.reject(new Error('Sem resposta do servidor. Verifique sua conexão.'));
    } else {
      // Erros de configuração
      return Promise.reject(new Error('Erro na requisição: ' + error.message));
    }
  }
);

export default {
  // CREATE
  criarCliente: (cliente) => api.post('/', cliente),
  
  // READ
  listarClientes: () => api.get('/'),
  buscarCliente: (id) => api.get(`/${id}`),
  
  // UPDATE
  atualizarCliente: (id, cliente) => api.put(`/${id}`, cliente),
  
  // DELETE
  deletarCliente: (id) => api.delete(`/${id}`),

  // Adicional para busca com filtros (exemplo)
  buscarClientesPorNome: (nome) => api.get(`/?nome=${encodeURIComponent(nome)}`)
};
